import { NavLink, useNavigate } from 'react-router-dom'
import { useAuth } from '../hooks/useAuth'
import { signOut } from '../lib/supabase'
import { LayoutDashboard, List, DollarSign, Users, LogOut, ChevronRight, History, Building2, Target } from 'lucide-react'

const nav = [
  { to: '/',        icon: LayoutDashboard, label: 'Dashboard' },
  { to: '/deals',   icon: List,            label: 'Deals'     },
  { to: '/clients', icon: Building2,       label: 'Clients'   },
  { to: '/history', icon: History,         label: 'History'   },
  { to: '/quotas',  icon: Target,          label: 'Sales Targets' },
  { to: '/budget',  icon: DollarSign,      label: 'Budget', adminOnly: true },
  { to: '/users',   icon: Users,           label: 'Users',  adminOnly: true },
]

export default function Layout({ children }) {
  const { profile, isAdmin } = useAuth()
  const navigate = useNavigate()

  async function handleSignOut() {
    await signOut()
    navigate('/login')
  }

  return (
    <div className="min-h-screen flex flex-col">
      {/* Top bar */}
      <header className="bg-navy text-white px-4 py-3 flex items-center justify-between sticky top-0 z-40 shadow-md">
        <div className="flex items-center gap-2.5 min-w-0">
          <img src="data:image/jpeg;base64,"
            alt="Business Book"
            className="shrink-0 rounded-full"
            style={{ width:38, height:38, objectFit:'cover', objectPosition:'center 15%' }}
          />
          <div className="flex flex-col leading-tight min-w-0">
            <span className="text-white text-sm font-semibold truncate tracking-wide">Business Book · FY26</span>
            <span className="text-white/50 text-[10px] font-medium hidden sm:block tracking-wide">by Elio Santos · Powered by AI</span>
          </div>
        </div>
        <div className="flex items-center gap-2 shrink-0">
          <span className="text-white/80 text-xs hidden sm:inline font-medium">{profile?.full_name || profile?.email}</span>
          <span className="text-white/80 text-xs sm:hidden font-medium truncate max-w-20">{(profile?.full_name || profile?.email || '').split(' ')[0]}</span>
          <span className={`text-xs px-2 py-0.5 rounded font-bold shrink-0 ${
            isAdmin ? 'bg-amber-400 text-amber-900' :
            profile?.role?.includes('vgt') ? 'bg-vgt text-white' :
            profile?.role?.includes('ect') ? 'bg-ect text-white' :
            profile?.role?.includes('viewer') ? 'bg-blue-500 text-white' : 'bg-gray-500 text-white'
          }`}>
            {profile?.role === 'admin' ? 'ADMIN' :
             profile?.role === 'vgt_editor' ? 'VGT' :
             profile?.role === 'ect_editor' ? 'ECT' :
             profile?.role === 'viewer_all' ? 'VIEWER' :
             profile?.role === 'viewer_vgt' ? 'VGT' :
             profile?.role === 'viewer_ect' ? 'ECT' :
             (profile?.role || '').toUpperCase()}
          </span>
          <button onClick={handleSignOut} className="text-white/60 hover:text-white transition-colors ml-1">
            <LogOut size={16} />
          </button>
        </div>
      </header>

      {/* Body */}
      <div className="flex flex-1">
        {/* Sidebar — desktop */}
        <aside className="hidden sm:flex flex-col w-52 bg-white border-r border-gray-100 py-4 gap-1 shrink-0">
          {nav.filter(n => !n.adminOnly || isAdmin).map(({ to, icon: Icon, label }) => (
            <NavLink key={to} to={to} end={to === '/'}
              className={({ isActive }) =>
                `flex items-center gap-3 mx-2 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors ${
                  isActive ? 'bg-navy text-white' : 'text-gray-600 hover:bg-gray-100'
                }`
              }>
              <Icon size={16} />
              {label}
              <ChevronRight size={14} className="ml-auto opacity-30" />
            </NavLink>
          ))}
          {/* BB Logo watermark at bottom of sidebar */}
          <div className="mt-auto px-3 pb-6 hidden sm:flex flex-col items-center gap-1 opacity-40 hover:opacity-80 transition-opacity duration-300">
            <img src="data:image/jpeg;base64,"
              alt="Business Book"
              style={{ width:110, borderRadius:8, objectFit:'cover', objectPosition:'center 15%', height:130 }}
            />
          </div>
        </aside>

        {/* Main content */}
        <main className="flex-1 overflow-y-auto pb-24 sm:pb-6 relative min-w-0">
          {/* Watermark */}
          <div className="pointer-events-none fixed inset-0 flex items-center justify-center z-0"
            style={{ left: typeof window !== 'undefined' && window.innerWidth >= 640 ? '13rem' : '0' }}>
            <img
              src="data:image/jpeg;base64,"
              alt=""
              style={{
                width: 'min(30vw, 300px)',
                opacity: 0.12,
                mixBlendMode: 'multiply',
                userSelect: 'none',
                pointerEvents: 'none',
              }}
            />
          </div>
          <div className="relative z-10">
            {children}
          </div>
        </main>
      </div>

      {/* Bottom nav — mobile */}
      <nav className="sm:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 flex z-40" style={{ paddingBottom: "env(safe-area-inset-bottom)" }}>
        {nav.filter(n => !n.adminOnly || isAdmin).map(({ to, icon: Icon, label }) => (
          <NavLink key={to} to={to} end={to === '/'}
            className={({ isActive }) =>
              `flex-1 flex flex-col items-center py-2 gap-0.5 text-xs font-medium transition-colors ${
                isActive ? 'text-navy' : 'text-gray-400'
              }`
            }>
            <Icon size={20} />
            {label}
          </NavLink>
        ))}
      </nav>
    </div>
  )
}
